const crypto = require('crypto');

const req = items[0]?.json ?? {};
const headers = req.headers || {};
const body = req.body || {};
const rawBody = typeof req.rawBody === 'string' && req.rawBody.length > 0
  ? req.rawBody
  : JSON.stringify(body);

const secret = $env.PADDLE_WEBHOOK_SECRET || '';
const paddleSig = headers['paddle-signature'] || headers['Paddle-Signature'] || '';

function parseSignatureHeader(sigHeader) {
  const out = {};
  for (const part of String(sigHeader || '').split(';')) {
    const [k, v] = part.split('=');
    if (k && v) out[k.trim()] = v.trim();
  }
  return out;
}

function safeEqualHex(a, b) {
  try {
    const ba = Buffer.from(String(a || ''), 'hex');
    const bb = Buffer.from(String(b || ''), 'hex');
    return ba.length === bb.length && crypto.timingSafeEqual(ba, bb);
  } catch {
    return false;
  }
}

function tryJsonParse(value) {
  try {
    return JSON.parse(value);
  } catch {
    return null;
  }
}

const sigParts = parseSignatureHeader(paddleSig);
const ts = Number(sigParts.ts || 0);
const h1 = sigParts.h1 || '';
const nowSec = Math.floor(Date.now() / 1000);
const tsFresh = ts > 0 && Math.abs(nowSec - ts) <= 300;

let signatureValid = false;
if (secret && h1 && tsFresh) {
  const signedPayload = `${ts}:${rawBody}`;
  const expected = crypto.createHmac('sha256', secret).update(signedPayload).digest('hex');
  signatureValid = safeEqualHex(expected, h1);
}

const eventType = body.event_type || body.eventType || '';
const eventId = String(body.event_id || body.notification_id || body.eventId || '').trim();
const data = body.data || {};

let passthrough = data.passthrough || data.custom_data?.passthrough || '';
if (typeof passthrough === 'string') {
  const parsed = tryJsonParse(passthrough);
  if (parsed && typeof parsed === 'object') passthrough = parsed;
}

const email = (
  data.customer?.email ||
  data.customer_email ||
  data.custom_data?.email ||
  data.custom_data?.user_email ||
  (typeof passthrough === 'object' ? passthrough.email : '') ||
  ''
).toLowerCase().trim();

const statusRaw = String(data.status || '').toLowerCase();
const paidByStatus = ['paid', 'completed', 'billed', 'active'].includes(statusRaw);
const paidByEvent = [
  'transaction.completed',
  'transaction.paid',
  'payment_succeeded',
  'subscription.created',
  'subscription.activated'
].includes(String(eventType || '').toLowerCase());

const amountRaw =
  data.details?.totals?.total ||
  data.totals?.total ||
  data.amount ||
  data.earnings ||
  null;
// Paddle Billing v2 returns totals in smallest currency unit (cents); divide by 100
const amountParsed = amountRaw == null ? null : Number(String(amountRaw).replace(',', '.'));
const paidAmount = Number.isFinite(amountParsed) ? +(amountParsed / 100).toFixed(2) : null;

const transactionId = String(data.id || data.transaction_id || data.order_id || '').trim();
const customerId = String(data.customer_id || data.customer?.id || '').trim();
const paymentDate = data.billed_at || data.created_at || body.occurred_at || new Date().toISOString();

const shouldProcess = Boolean(secret && signatureValid && email && (paidByStatus || paidByEvent));

return [{
  json: {
    should_process: shouldProcess,
    event_id: eventId,
    reason: shouldProcess
      ? 'verified_paid_event'
      : 'ignored_event_or_invalid_signature',
    event_type: eventType,
    email,
    paid_amount: Number.isFinite(paidAmount) ? paidAmount : null,
    transaction_id: transactionId,
    customer_id: customerId,
    payment_date: paymentDate,
    signature_present: Boolean(paddleSig),
    signature_valid: signatureValid
  }
}];

const paidLead = $('Mark Lead as Paid').first().json || {};
const profileRaw = paidLead.user_profile;
const profile = typeof profileRaw === 'string' ? JSON.parse(profileRaw || '{}') : (profileRaw || {});
const email = paidLead.email;

const mvTypeNorm = {
  resistance: 'strength',
  'resistance / strength': 'strength',
  'balanced routine': 'mix',
  mix: 'mix',
  'cardio-based': 'cardio',
  'yoga / pilates': 'mobility',
  'yoga / pilates / dance': 'mobility',
  'yoga/pilates': 'mobility'
};
const userMovType = mvTypeNorm[profile.movement_type] || profile.movement_type;

const spaceMap = {
  indoor: ['close_space', 'all'],
  outdoors: ['outdoors', 'open_space', 'all'],
  mixed: ['close_space', 'outdoors', 'open_space', 'all']
};
const allowedSpaces = spaceMap[profile.space] || ['all'];

const equipMap = {
  none: ['none'],
  everyday_items: ['none', 'everyday_items', 'backpack']
};
const allowedEquip = equipMap[profile.equipment] || ['none'];

const levelProgress = {
  beginner: [['beginner'], ['beginner'], ['beginner'], ['beginner']],
  intermediate: [['beginner'], ['beginner', 'intermediate'], ['intermediate'], ['intermediate', 'advanced']],
  advanced: [['intermediate'], ['intermediate', 'advanced'], ['advanced'], ['advanced']]
};
const weekLevels = levelProgress[profile.level] || levelProgress.beginner;

const contraPainKeywords = (profile.contraindications || [])
  .filter(c => c !== 'stress')
  .map(c => {
    if (c === 'low_back_pain') return 'low back';
    if (c === 'knee_pain') return 'knee';
    if (c === 'shoulders_pain') return 'shoulders';
    return c.replace(/_/g, ' ');
  });

const excludeHighIntensity =
  (profile.contraindications || []).includes('stress') ||
  profile.sleep_bucket === 'very_low' ||
  (profile.sex === 'female' && ['menstrual', 'luteal'].includes(profile.cycle_phase));

const allExercises = [
  ...($('Fetch Exercises p1').first().json.list || []),
  ...($('Fetch Exercises p2').first().json.list || []),
  ...($('Fetch Exercises p3').first().json.list || []),
  ...($('Fetch Exercises p4').first().json.list || [])
];

function matchesContra(ex) {
  if (contraPainKeywords.length === 0) return true;
  if (!ex.contraindications) return true;
  const exContra = ex.contraindications.toLowerCase();
  return !contraPainKeywords.some(k => exContra.includes(k));
}

function getWarmupPool() {
  return allExercises.filter(ex => {
    if (ex.primary_goal !== 'warmup') return false;
    if (!allowedSpaces.includes(ex.space)) return false;
    if (!allowedEquip.includes(ex.equipment)) return false;
    if (!matchesContra(ex)) return false;
    if (excludeHighIntensity && ex.intensity === 'high') return false;
    return true;
  });
}

function getMainPool(goal, weekLevel, minCount = 4) {
  function baseFilter(ex) {
    if (ex.primary_goal !== goal) return false;
    if (!allowedSpaces.includes(ex.space)) return false;
    if (!allowedEquip.includes(ex.equipment)) return false;
    if (!weekLevel.includes(ex.level)) return false;
    if (!matchesContra(ex)) return false;
    if (excludeHighIntensity && ex.intensity === 'high') return false;
    return true;
  }
  if (userMovType && userMovType !== 'mix') {
    const withType = allExercises.filter(ex => {
      if (!baseFilter(ex)) return false;
      const exTypes = (ex.movement_type || '').split(',').map(s => s.trim());
      return exTypes.includes(userMovType);
    });
    if (withType.length >= minCount) return withType;
  }
  return allExercises.filter(baseFilter);
}

const fallbackMap = {
  energy: ['energy', 'active'],
  active: ['active', 'energy'],
  destress: ['destress', 'posture', 'core'],
  posture: ['posture', 'destress', 'core'],
  core: ['core', 'destress', 'posture']
};
const goalFallbacks = fallbackMap[profile.primary_goal] || [profile.primary_goal];

const slotBodyFocus = {
  energy: [['full_body'], ['upper_body', 'full_body'], ['full_body'], ['full_body']],
  destress: [['full_body'], ['upper_body', 'full_body'], ['full_body'], ['full_body']],
  posture: [['full_body'], ['lower_body', 'full_body'], ['upper_body', 'full_body'], ['full_body']],
  active: [['lower_body', 'full_body'], ['upper_body', 'full_body'], ['full_body'], ['full_body']],
  core: [['full_body'], ['lower_body', 'full_body'], ['full_body'], ['full_body']]
};
const bodyFocusRules = slotBodyFocus[profile.primary_goal]
  || [['full_body'], ['full_body'], ['full_body'], ['full_body']];

const sessions = ['morning', 'midday', 'afternoon', 'evening'];

function pickRandom(arr) {
  if (!arr || arr.length === 0) return null;
  return arr[Math.floor(Math.random() * arr.length)];
}

const globalUsedMainIds = new Set();
const warmupPool = getWarmupPool();
const plan = {};

for (let w = 0; w < 4; w++) {
  const weekNum = w + 1;
  const weekLevel = weekLevels[w];

  let mainPool = [];
  for (const goal of goalFallbacks) {
    const pool = getMainPool(goal, weekLevel);
    const fresh = pool.filter(e => !mainPool.find(m => m.ex_id === e.ex_id));
    mainPool = [...mainPool, ...fresh];
    if (mainPool.length >= 4) break;
  }

  const freshMain = mainPool.filter(e => !globalUsedMainIds.has(e.ex_id));
  const effectiveMain = freshMain.length >= 4 ? freshMain : mainPool;

  const weekUsedWarmupIds = new Set();
  const weekUsedMainIds = new Set();
  const weekPlan = {};

  for (let s = 0; s < 4; s++) {
    const warmupCandidates = warmupPool.filter(e => !weekUsedWarmupIds.has(e.ex_id));
    const wu = pickRandom(warmupCandidates.length > 0 ? warmupCandidates : warmupPool);
    if (wu) weekUsedWarmupIds.add(wu.ex_id);

    const slotFocus = bodyFocusRules[s];
    let mainCandidates = effectiveMain.filter(e =>
      !weekUsedMainIds.has(e.ex_id) && slotFocus.includes(e.body_focus)
    );
    if (mainCandidates.length === 0) {
      mainCandidates = effectiveMain.filter(e => !weekUsedMainIds.has(e.ex_id));
    }
    if (mainCandidates.length === 0) {
      mainCandidates = mainPool;
    }
    const mx = pickRandom(mainCandidates);
    if (mx) {
      weekUsedMainIds.add(mx.ex_id);
      globalUsedMainIds.add(mx.ex_id);
    }

    weekPlan[sessions[s]] = {
      warmup: wu ? {
        ex_id: wu.ex_id,
        name: wu.name,
        description: wu.description,
        body_focus: wu.body_focus,
        level: wu.level,
        intensity: wu.intensity,
        movement_type: wu.movement_type,
        image_url: wu.image_url || wu.imageUrl || wu.image || wu.photo_url || wu.photoUrl || '',
        cues: wu.cues
      } : null,
      main: mx ? {
        ex_id: mx.ex_id,
        name: mx.name,
        description: mx.description,
        body_focus: mx.body_focus,
        level: mx.level,
        intensity: mx.intensity,
        movement_type: mx.movement_type,
        primary_goal: mx.primary_goal,
        image_url: mx.image_url || mx.imageUrl || mx.image || mx.photo_url || mx.photoUrl || '',
        cues: mx.cues
      } : null
    };
  }
  plan[`week_${weekNum}`] = weekPlan;
}

return [{ json: { program_plan: plan, email } }];

const planData = $('Build Program Plan').first().json;
const paidLead = $('Mark Lead as Paid').first().json || {};
const profileRaw = paidLead.user_profile;
const profile = typeof profileRaw === 'string' ? JSON.parse(profileRaw || '{}') : (profileRaw || {});
const programPlan = planData.program_plan || {};
const weekNum = 1;
const weekKey = 'week_1';
const weekPlan = programPlan[weekKey] || {};

const sessions = ['morning', 'midday', 'afternoon', 'evening'];
const weekPlanForPdf = {};
for (const s of sessions) {
  const slot = weekPlan[s] || {};
  weekPlanForPdf[s] = {
    warmup: slot.warmup ? {
      name: slot.warmup.name,
      description: slot.warmup.description,
      image_url: slot.warmup.image_url || slot.warmup.imageUrl || slot.warmup.image || slot.warmup.photo_url || slot.warmup.photoUrl || '',
      cues: slot.warmup.cues
    } : null,
    main: slot.main ? {
      name: slot.main.name,
      description: slot.main.description,
      image_url: slot.main.image_url || slot.main.imageUrl || slot.main.image || slot.main.photo_url || slot.main.photoUrl || '',
      cues: slot.main.cues
    } : null
  };
}

const calendarMap = {
  1: $env.CALENDAR_WEEK1_URL || '',
  2: $env.CALENDAR_WEEK2_URL || '',
  3: $env.CALENDAR_WEEK3_URL || '',
  4: $env.CALENDAR_WEEK4_URL || ''
};

return [{
  json: {
    name: paidLead.name || 'there',
    email: paidLead.email,
    week_number: weekNum,
    template_key: weekKey,
    week_plan: weekPlanForPdf,
    profile,
    calendar_url: calendarMap[weekNum] || $env.CALENDAR_DEFAULT_URL || ''
  }
}];

const payload = $('Build PDF Payload').first().json;
const template = $('Load Email Template').first().json;

function fill(str, vars) {
  let out = String(str || '');
  for (const [k, v] of Object.entries(vars)) {
    const re = new RegExp('\\{\\{' + k + '\\}\\}', 'g');
    out = out.replace(re, String(v ?? ''));
  }
  return out;
}

const vars = {
  name: payload.name || 'there',
  week_number: payload.week_number,
  calendar_url: payload.calendar_url || '',
  week_pdf_url: '',
  level2_offer_url: $env.LEVEL2_OFFER_URL || '',
  goal: payload.goal || payload.profile?.primary_goal || payload.profile?.goal || ''
};

return [{
  json: {
    ...payload,
    email_subject: fill(template.subject, vars),
    email_html: fill(template.html, vars),
    attachment_filename: `week${payload.week_number}-plan.pdf`
  }
}];

